export function nextGeneration(grid: number[][]): number[][] {
  const key = (x: number, y: number) => `${x},${y}`;
  const live = new Set(grid.map(([x, y]) => key(x, y)));
  const neighborCounts = new Map<string, number>();

  for (const [x, y] of grid) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const k = key(x + dx, y + dy);
        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
      }
    }
  }

  const nextLive: number[][] = [];
  for (const [k, count] of neighborCounts) {
    const isAlive = live.has(k);
    if (count === 3 || (isAlive && count === 2)) {
      const [x, y] = k.split(",").map(Number);
      nextLive.push([x, y]);
    }
  }
  return nextLive;
}

