type Cell = readonly [number, number];

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

export function nextGeneration(grid: number[][]): number[][] {
  const liveCellKeys = new Set(grid.map((cell) => cellKey(cell as Cell)));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of grid) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighbor: Cell = [x + dx, y + dy];
        const k = cellKey(neighbor);
        const existing = neighborCounts.get(k);
        neighborCounts.set(k, { cell: neighbor, count: (existing?.count ?? 0) + 1 });
      }
    }
  }

  const nextLive: number[][] = [];
  for (const [k, { cell, count }] of neighborCounts) {
    const isAlive = liveCellKeys.has(k);
    const survives = isAlive && count === 2;
    const reproduces = count === 3;
    if (survives || reproduces) {
      nextLive.push([cell[0], cell[1]]);
    }
  }
  return nextLive;
}

